export const DnbDefault: LogoSvgComponent = function ({
  alt = DnbDefault.alt,
  fill,
  ...props
}) {
  const theme = useTheme()
  const isDark = theme?.colorScheme === 'dark'
  const resolvedFill =
    fill ?? (isDark ? logoColors.dnb.dark : logoColors.dnb.light)

  return (
    <svg fill={resolvedFill} {...props} viewBox="0 0 116 80">
      <title>{alt}</title>
      <DnbPaths />
    </svg>
  )
}
DnbDefault.brand = 'ui'
DnbDefault.alt = logoAlts.dnb

